<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> tail_clean </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">content</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -</span><span style="color:#FAB387;"> TRUNCATION_KEEP_TAIL</span><span style="color:#94E2D5;"> +</span><span style="color:#CDD6F4;"> tail_start</span><span style="color:#94E2D5;">..</span><span style="color:#9399B2;">];</span></span>
