<span class="line"><span style="color:#CDD6F4;">        total_result_tokens </span><span style="color:#94E2D5;">+=</span><span style="color:#CDD6F4;"> formatted_content</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> /</span><span style="color:#FAB387;"> 4</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;"> // rough estimate</span></span>
