<span class="line"><span style="color:#CDD6F4;">        any_errors</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> raw_results</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">iter</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">any</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">r</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> r</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">is_error</span><span style="color:#9399B2;">),</span></span>
